const { LoggerService } = require("../src/services/LoggerService");
const winston = require("winston");

describe("LoggerService", () => {
    let logger;
    let logSpy, errorSpy;

    beforeEach(() => {
        logger = new LoggerService("TestService");

        // Mock Winston logger methods
        logSpy = jest.spyOn(logger.logger, "info").mockImplementation(() => {});
        errorSpy = jest.spyOn(logger.logger, "error").mockImplementation(() => {});
    });

    afterEach(() => {
        jest.restoreAllMocks();
    });

    test("should log an info message", () => {
        logger.info("Test Info Log");
        expect(logSpy).toHaveBeenCalledWith("Test Info Log");
    });

    test("should log an error message", () => {
        logger.error("Test Error Log");
        expect(errorSpy).toHaveBeenCalledWith("Test Error Log");
    });
});
